  ('disabled-6f0ba476-moex-00236', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '假設市場勞動需求曲線為負斜率，而勞動供給曲線則為正斜率，同時假設 目前勞動供給曲線和需求曲線相交時的工資低於目前的基本工資。如果基 本工資調升時，有關對勞動市場影響的敘述，下列何者錯誤？', '["勞動需求量會下降", "勞動需求會下降", "就業人數會減少", "失業率會上升"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": "aff3e98fba69", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
