  ('disabled-6f0ba476-moex-00238', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-113-d3ff7f6b', 'sub-disabled-6f0ba476-07', NULL, 'single_choice', '假設一個經濟社會共有貨幣、勞動、產品、股票、房地產等五個市場，依 據瓦拉斯法則（Walras’law），下列敘述何者正確？', '["瓦拉斯法則屬於部分均衡分析", "除了貨幣市場，其餘四個市場的超額需求加總為0", "除了勞動市場，其餘四個市場的超額需求加總為0", "當貨幣市場有超額供給，可能會造成一般物價、薪資、股價或房價的上漲"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:28+00:00", "source_pdf_sha1": "6f76ab1b056f", "answer_pdf_sha1": "aff3e98fba69", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "305", "s": "0902", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
